const t=JSON.parse('{"key":"v-36c1f7ee","path":"/poetry/2013/","title":"登高望远，夜幕降临","lang":"zh-CN","frontmatter":{"description":"写于 2013年8月1日 夜幕即将降临，骑上单车，穿过那片田野。 来到山脚下，惊动雏鸟，鸟儿藏匿。 回望田野，阡陌纵横。 登上山顶，凉风袭来。 遥望夕阳，静观晚霞。 环顾四周，村落人家，炊烟缕缕。 万里群山，千姿百态。 山谷松木，郁郁葱葱。 忽见蛇行，匆匆击掌，惊起白鹤数只。 远处湖泊，听到车声，定睛一看，原是高速路。 天空鸟儿飞过，叫声凄凉，归栖息地...","head":[["meta",{"property":"og:url","content":"https://lxchuan12.cn/poetry/2013/"}],["meta",{"property":"og:site_name","content":"若川的博客"}],["meta",{"property":"og:title","content":"登高望远，夜幕降临"}],["meta",{"property":"og:description","content":"写于 2013年8月1日 夜幕即将降临，骑上单车，穿过那片田野。 来到山脚下，惊动雏鸟，鸟儿藏匿。 回望田野，阡陌纵横。 登上山顶，凉风袭来。 遥望夕阳，静观晚霞。 环顾四周，村落人家，炊烟缕缕。 万里群山，千姿百态。 山谷松木，郁郁葱葱。 忽见蛇行，匆匆击掌，惊起白鹤数只。 远处湖泊，听到车声，定睛一看，原是高速路。 天空鸟儿飞过，叫声凄凉，归栖息地..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://lxchuan12.cn/"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2019-11-10T07:19:25.000Z"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:image:alt","content":"登高望远，夜幕降临"}],["meta",{"property":"article:author","content":"若川"}],["meta",{"property":"article:modified_time","content":"2019-11-10T07:19:25.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"登高望远，夜幕降临\\",\\"image\\":[\\"https://lxchuan12.cn/\\"],\\"dateModified\\":\\"2019-11-10T07:19:25.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"若川\\",\\"url\\":\\"https://lxchuan12.cn\\"}]}"]]},"headers":[],"git":{"createdTime":1573370365000,"updatedTime":1573370365000,"contributors":[{"name":"luoxiaochuan","email":"luoxiaochuan@comteck.cn","commits":1}]},"readingTime":{"minutes":0.72,"words":216},"filePathRelative":"poetry/2013/README.md","localizedDate":"2019年11月10日","copyright":{"author":"若川"},"autoDesc":true,"excerpt":""}');export{t as data};
